const QUESTIONS_CISSP_C2 = [
  { id:30301, domain:3, level:2, question:"Which security model enforces confidentiality by preventing subjects from reading data at a higher classification level?", options:["A Clark-Wilson model","B Biba model","C Bell-LaPadula model","D Brewer-Nash model"], correct:2, explanation:"Bell-LaPadula enforces confidentiality with 'no read up' (simple security property) and 'no write down' (star property), preventing subjects from reading above their clearance level." },
  { id:30302, domain:3, level:2, question:"What does the Clark-Wilson integrity model primarily protect against?", options:["A Unauthorized disclosure of classified data","B Unauthorized modification of data by enforcing well-formed transactions","C Denial of service attacks on critical systems","D Replay attacks in network communications"], correct:1, explanation:"Clark-Wilson protects data integrity by requiring all changes go through certified transformation procedures (TPs), ensuring only well-formed transactions occur." },
  { id:30303, domain:3, level:1, question:"Which evaluation criteria provides a common set of requirements for security products recognized internationally?", options:["A FIPS 140-2","B ISO/IEC 27001","C TCSEC (Orange Book)","D Common Criteria (ISO 15408)"], correct:3, explanation:"Common Criteria (ISO/IEC 15408) is an internationally recognized framework allowing security products to be evaluated against defined Protection Profiles and Evaluation Assurance Levels." },
  { id:30304, domain:3, level:2, question:"What is the primary purpose of a Trusted Platform Module (TPM)?", options:["A Encrypting all data on a network segment","B Managing user authentication for enterprise applications","C Providing hardware-based cryptographic key storage and platform integrity measurement","D Generating pseudo-random numbers for session tokens"], correct:2, explanation:"A TPM is a hardware chip that securely stores cryptographic keys and measures platform integrity through hash values, enabling trusted boot and remote attestation." },
  { id:30305, domain:3, level:2, question:"Which type of cipher operates on fixed-size blocks of data, transforming each block using the same key?", options:["A Stream cipher","B Substitution cipher","C One-time pad","D Block cipher"], correct:3, explanation:"Block ciphers (e.g., AES, DES) process fixed-size blocks of plaintext and produce fixed-size ciphertext blocks, using the same key for each block transformation." },
  { id:30306, domain:3, level:2, question:"What is the purpose of cipher block chaining (CBC) mode in block cipher encryption?", options:["A To increase the key size for stronger encryption","B To reduce the computational overhead of block encryption","C To XOR each plaintext block with the previous ciphertext block before encryption","D To allow parallel processing of all cipher blocks simultaneously"], correct:2, explanation:"In CBC mode, each plaintext block is XORed with the preceding ciphertext block before encryption, ensuring identical plaintext blocks produce different ciphertext and providing error propagation." },
  { id:30307, domain:3, level:1, question:"Which cryptographic algorithm is considered asymmetric?", options:["A AES-256","B RSA","C 3DES","D Blowfish"], correct:1, explanation:"RSA is an asymmetric algorithm using a public/private key pair. AES-256, 3DES, and Blowfish are all symmetric algorithms using a single shared secret key." },
  { id:30308, domain:3, level:2, question:"What is the primary security advantage of elliptic curve cryptography (ECC) over RSA?", options:["A ECC provides stronger encryption with shorter key lengths","B ECC is easier to implement in software than RSA","C ECC supports digital signatures but RSA does not","D ECC is not vulnerable to man-in-the-middle attacks"], correct:0, explanation:"ECC provides equivalent security to RSA with significantly shorter key lengths (e.g., 256-bit ECC ≈ 3072-bit RSA), making it more efficient for mobile and constrained devices." },
  { id:30309, domain:3, level:2, question:"Which principle states that a system should have the minimum number of trusted components necessary to enforce security policy?", options:["A Least privilege","B Economy of mechanism","C Defense in depth","D Separation of duties"], correct:1, explanation:"Economy of mechanism (also called simplicity) states that security mechanisms should be as simple as possible, reducing the trusted computing base and minimizing potential vulnerabilities." },
  { id:30310, domain:3, level:2, question:"What does 'open design' mean as a security design principle?", options:["A Security relies on the secrecy of the design and algorithms","B Source code is publicly available for peer review","C The system is accessible to all users without authentication","D Security does not depend on secrecy of the design; only keys are secret"], correct:3, explanation:"Open design principle states that system security should not rely on keeping the design secret (security through obscurity). Only the keys should be kept secret, making algorithms publicly scrutinizable." },
  { id:30311, domain:3, level:2, question:"In the context of security architecture, what is the Trusted Computing Base (TCB)?", options:["A The totality of protection mechanisms within a computer system responsible for enforcing security policy","B The group of security administrators managing the system","C The set of all hardware components in a secure system","D All data classified as sensitive within an organization"], correct:0, explanation:"The TCB is the combination of all hardware, software, and firmware that enforces the security policy of a system. Minimizing the TCB reduces the attack surface and simplifies verification." },
  { id:30312, domain:3, level:1, question:"Which type of malware replicates itself by attaching to legitimate programs and spreads when those programs are executed?", options:["A Virus","B Worm","C Trojan horse","D Rootkit"], correct:0, explanation:"A virus attaches itself to legitimate host programs and requires user action (executing the host program) to spread. Worms spread without user interaction; trojans disguise as legitimate software; rootkits hide their presence." },
  { id:30313, domain:3, level:2, question:"What is the primary difference between a worm and a virus?", options:["A Worms encrypt files while viruses delete them","B Worms self-replicate across networks without requiring a host file","C Viruses target network devices while worms target endpoints","D Worms require administrator privileges while viruses do not"], correct:1, explanation:"Worms are self-contained programs that replicate and spread across networks independently without needing to attach to host files. Viruses require host programs to propagate." },
  { id:30314, domain:3, level:2, question:"Which vulnerability allows an attacker to execute arbitrary commands by manipulating input that is passed to a system shell?", options:["A Command injection","B SQL injection","C Cross-site scripting","D Directory traversal"], correct:0, explanation:"Command injection occurs when user-supplied input is passed unsanitized to a system shell or interpreter, allowing attackers to execute arbitrary OS commands with the application's privileges." },
  { id:30315, domain:3, level:2, question:"What is a race condition vulnerability in software?", options:["A Software that runs slower than expected under load","B A flaw where system behavior depends on the timing of uncontrollable events","C An error caused by exceeding memory allocation limits","D A condition where two processes compete for limited CPU cycles"], correct:1, explanation:"Race conditions occur when system behavior depends on the sequence or timing of events (e.g., two processes accessing shared data simultaneously), potentially leading to security exploits like TOCTOU attacks." },
  { id:30316, domain:4, level:2, question:"Which OSI layer is responsible for end-to-end communication and error recovery between hosts?", options:["A Data Link layer (Layer 2)","B Network layer (Layer 3)","C Session layer (Layer 5)","D Transport layer (Layer 4)"], correct:3, explanation:"The Transport layer (Layer 4) provides end-to-end communication services, error recovery, flow control, and multiplexing. TCP and UDP operate at this layer." },
  { id:30317, domain:4, level:1, question:"What is the primary purpose of Network Address Translation (NAT)?", options:["A To map private IP addresses to public IP addresses for internet communication","B To route packets between different network segments","C To encrypt traffic between internal and external networks","D To authenticate users before granting network access"], correct:0, explanation:"NAT allows multiple devices with private IP addresses to share a single public IP address, conserving public IP space and providing a degree of network address obscuration." },
  { id:30318, domain:4, level:2, question:"Which protocol provides authentication and encryption for IP packets at the network layer?", options:["A IPSec","B SSL/TLS","C HTTPS","D SSH"], correct:0, explanation:"IPSec operates at the Network layer (Layer 3) and provides authentication (AH header) and encryption (ESP header) for IP packets, securing communication at the network level." },
  { id:30319, domain:4, level:2, question:"In IPSec, what is the difference between Transport mode and Tunnel mode?", options:["A Transport mode encrypts the entire IP packet; Tunnel mode encrypts only the payload","B Transport mode is used for host-to-host; Tunnel mode is only for site-to-site VPNs","C Transport mode encrypts only the payload; Tunnel mode encapsulates the entire original IP packet","D Transport mode uses AH; Tunnel mode uses ESP"], correct:2, explanation:"In Transport mode, only the IP payload is protected; the original IP header remains intact. In Tunnel mode, the entire original IP packet is encapsulated within a new IP packet with a new header, commonly used for VPNs." },
  { id:30320, domain:4, level:2, question:"Which wireless security protocol uses the CCMP encryption mode based on AES?", options:["A WPA2/WPA3","B WPA (TKIP)","C WEP","D WPS"], correct:0, explanation:"WPA2 (and WPA3) use CCMP (Counter Mode with CBC-MAC Protocol), which is based on AES-128, providing strong encryption and integrity protection. WPA uses TKIP; WEP uses RC4." },
  { id:30321, domain:4, level:1, question:"What type of attack involves intercepting and modifying communications between two parties without their knowledge?", options:["A Replay attack","B Session hijacking","C Denial of service attack","D Man-in-the-middle attack"], correct:3, explanation:"A man-in-the-middle (MITM) attack occurs when an attacker secretly intercepts and potentially alters communication between two parties, who believe they are communicating directly with each other." },
  { id:30322, domain:4, level:2, question:"What is the primary function of a proxy firewall (application layer gateway)?", options:["A Filtering packets based solely on source and destination IP addresses","B Providing stateful inspection of TCP session state","C Terminating and re-establishing connections while inspecting application layer data","D Encrypting all traffic passing through the network perimeter"], correct:2, explanation:"Proxy firewalls (application layer gateways) terminate client connections, inspect application-layer content, and create new connections to the destination, providing deep content inspection and hiding internal network topology." },
  { id:30323, domain:4, level:2, question:"Which network attack exploits the trust relationship between IP addresses by falsifying the source address in packets?", options:["A IP spoofing","B ARP poisoning","C DNS hijacking","D MAC flooding"], correct:0, explanation:"IP spoofing involves crafting packets with forged source IP addresses to impersonate trusted hosts, bypass access controls, or facilitate other attacks while hiding the attacker's true identity." },
  { id:30324, domain:4, level:2, question:"What does 802.1X provide in a network security context?", options:["A Wireless encryption using CCMP/AES","B Port-based network access control requiring authentication before granting access","C VLAN configuration and management for network segmentation","D Quality of service prioritization for network traffic"], correct:1, explanation:"IEEE 802.1X provides port-based Network Access Control (PNAC), requiring devices to authenticate (typically via EAP) through an authentication server before being granted network access." },
  { id:30325, domain:4, level:2, question:"What is a botnet?", options:["A A collection of compromised computers controlled by an attacker for malicious purposes","B A network of servers providing distributed computing resources","C A type of intrusion detection system using agent-based monitoring","D A secure overlay network for anonymous communications"], correct:0, explanation:"A botnet is a network of malware-infected computers (bots/zombies) controlled by a command-and-control server. Attackers use botnets for spam, DDoS attacks, credential theft, and other malicious activities." },
  { id:30326, domain:4, level:1, question:"Which protocol is primarily used to dynamically assign IP addresses to network devices?", options:["A DHCP","B ICMP","C ARP","D DNS"], correct:0, explanation:"Dynamic Host Configuration Protocol (DHCP) automatically assigns IP addresses, subnet masks, default gateways, and other network parameters to devices when they connect to a network." },
  { id:30327, domain:4, level:2, question:"What security weakness does DHCP snooping address?", options:["A ARP spoofing attacks on the local network segment","B DNS cache poisoning attacks on the network","C Rogue DHCP servers distributing malicious network configuration to clients","D MAC address flooding that overwhelms switch tables"], correct:2, explanation:"DHCP snooping is a switch security feature that filters DHCP messages, allowing only trusted DHCP server responses, preventing rogue DHCP servers from distributing incorrect gateway or DNS information to clients." },
  { id:30328, domain:4, level:2, question:"Which attack type exhausts server resources by sending SYN packets without completing the TCP three-way handshake?", options:["A UDP flood attack","B Fraggle attack","C Smurf attack","D SYN flood attack"], correct:3, explanation:"A SYN flood attack sends many TCP SYN packets without completing the handshake, filling the server's connection queue with half-open connections and exhausting resources, causing denial of service." },
  { id:30329, domain:4, level:2, question:"What is the purpose of BGP (Border Gateway Protocol) route filtering?", options:["A To encrypt routing information between autonomous systems","B To authenticate OSPF adjacencies between routers","C To optimize packet forwarding within a single network","D To prevent the propagation of invalid or malicious routing information between networks"], correct:3, explanation:"BGP route filtering controls which routes are accepted from and advertised to neighbors, preventing route hijacking, prefix hijacking, and the propagation of misconfigured or malicious routing information." },
  { id:30330, domain:4, level:2, question:"What does the term 'split tunneling' refer to in VPN configurations?", options:["A Dividing VPN traffic between multiple tunnels for load balancing","B Creating separate encrypted channels for different security classifications","C Allowing some traffic to go through the VPN while other traffic routes directly to the internet","D Splitting the VPN key between two administrators for dual control"], correct:2, explanation:"Split tunneling allows VPN users to send organization-bound traffic through the encrypted VPN tunnel while routing internet-bound traffic directly to the internet, bypassing the VPN, which may reduce security visibility." },
  { id:30331, domain:5, level:1, question:"Which access control model grants access based on the subject's clearance level and the object's classification label?", options:["A Discretionary Access Control (DAC)","B Role-Based Access Control (RBAC)","C Mandatory Access Control (MAC)","D Attribute-Based Access Control (ABAC)"], correct:2, explanation:"Mandatory Access Control (MAC) grants access based on security labels assigned to subjects (clearances) and objects (classifications). The system, not the owner, enforces access decisions based on policy." },
  { id:30332, domain:5, level:1, question:"In Role-Based Access Control (RBAC), permissions are assigned to what primary entity?", options:["A Roles, which are then assigned to users","B Individual user accounts","C Security groups based on department","D Objects based on their sensitivity classification"], correct:0, explanation:"In RBAC, permissions are assigned to roles (job functions), and users are assigned to roles. This simplifies administration since changing permissions for a job function only requires updating the role." },
  { id:30333, domain:5, level:2, question:"What is the primary advantage of Attribute-Based Access Control (ABAC) over traditional RBAC?", options:["A ABAC provides fine-grained access control based on multiple attributes of users, resources, and environment","B ABAC is simpler to implement and administer than RBAC","C ABAC eliminates the need for authentication before authorization","D ABAC is the only model compliant with government security regulations"], correct:0, explanation:"ABAC evaluates multiple attributes (user attributes, resource attributes, environmental conditions) to make access decisions, enabling very granular policies like 'grant access only during business hours from corporate devices.'" },
  { id:30334, domain:5, level:2, question:"What is the purpose of an Identity Provider (IdP) in federated identity management?", options:["A To store and manage all application user databases","B To authenticate users and assert their identity to relying parties via trust relationships","C To encrypt all communications between users and applications","D To provision user accounts in multiple systems simultaneously"], correct:1, explanation:"An Identity Provider authenticates users, maintains their identity information, and provides identity assertions (tokens/claims) to relying party services (Service Providers), enabling Single Sign-On across federated systems." },
  { id:30335, domain:5, level:2, question:"Which authentication protocol is commonly used for web-based Single Sign-On, issuing tokens rather than passwords?", options:["A SAML (Security Assertion Markup Language)","B Kerberos","C RADIUS","D LDAP"], correct:0, explanation:"SAML is an XML-based open standard for exchanging authentication and authorization data between identity providers and service providers, enabling browser-based SSO by passing XML assertions." },
  { id:30336, domain:5, level:2, question:"In Kerberos authentication, what is the primary role of the Ticket Granting Service (TGS)?", options:["A To verify the user's initial identity and issue a Ticket Granting Ticket","B To issue service tickets for specific resources after presenting a valid TGT","C To store the master database of all user credentials and secrets","D To encrypt all network traffic between client and server"], correct:1, explanation:"The TGS issues service tickets for specific services when clients present a valid Ticket Granting Ticket (TGT). The TGT is issued by the Authentication Service (AS) after initial authentication." },
  { id:30337, domain:5, level:2, question:"What is the concept of 'just-in-time' access provisioning in privileged access management?", options:["A Provisioning user accounts immediately upon hire without delay","B Automatically revoking access after a fixed time period regardless of activity","C Granting elevated privileges only when needed and automatically removing them after the task","D Scheduling privileged access reviews on a regular calendar basis"], correct:2, explanation:"Just-in-time access grants privileged access temporarily for specific tasks and automatically revokes it afterward, minimizing the exposure window for privileged accounts and following the principle of least privilege." },
  { id:30338, domain:5, level:2, question:"What does OAuth 2.0 primarily provide?", options:["A Authentication of user identity for web applications","B Authorization framework allowing third-party applications to access resources without sharing credentials","C Encryption of data transmitted between clients and APIs","D Digital signature verification for software packages"], correct:1, explanation:"OAuth 2.0 is an authorization framework that enables applications to obtain limited access to user accounts on another service using access tokens, without exposing user credentials to the third-party application." },
  { id:30339, domain:5, level:2, question:"Which biometric characteristic has the highest uniqueness and is considered among the most reliable for authentication?", options:["A Fingerprint","B Iris pattern","C Voice recognition","D Facial geometry"], correct:1, explanation:"Iris patterns are highly unique (even between identical twins and between left/right eyes), stable over time, and difficult to forge, making iris recognition among the most accurate biometric methods." },
  { id:30340, domain:5, level:2, question:"What does the Crossover Error Rate (CER) measure in biometric systems?", options:["A The maximum number of authentication attempts before lockout","B The point where false acceptance rate equals false rejection rate, indicating overall accuracy","C The rate at which enrolled users lose their biometric credentials over time","D The percentage of biometric data compromised in a breach"], correct:1, explanation:"CER (also called Equal Error Rate or EER) is the point where FAR equals FRR. A lower CER indicates a more accurate biometric system. It is used to compare the accuracy of different biometric technologies." },
  { id:30341, domain:5, level:2, question:"What is the primary security concern with password hash storage using MD5 or SHA-1?", options:["A These algorithms produce hashes that are too short for adequate security","B These algorithms are fast, making brute-force and rainbow table attacks efficient","C These algorithms cannot be used with salting to improve security","D These algorithms produce reversible hashes that reveal the original password"], correct:1, explanation:"MD5 and SHA-1 are fast general-purpose hashes. Their speed makes them unsuitable for passwords because attackers can compute billions of hash attempts per second. Password hashing should use slow functions like bcrypt or Argon2." },
  { id:30342, domain:5, level:2, question:"Which provisioning process ensures that access rights are removed when an employee leaves an organization?", options:["A Deprovisioning","B Access recertification","C Access certification","D Privilege escalation review"], correct:0, explanation:"Deprovisioning is the process of revoking a user's access rights, disabling accounts, and removing privileges when they leave the organization or change roles, preventing unauthorized access after separation." },
  { id:30343, domain:5, level:1, question:"What is the 'something you have' authentication factor?", options:["A A biometric characteristic unique to the individual","B A password or PIN known only to the user","C A physical token, smart card, or mobile device possessed by the user","D A location-based check verifying the user's position"], correct:2, explanation:"'Something you have' is a possession factor—a physical item like a hardware token, smart card, key fob, or mobile authenticator app. Multi-factor authentication combines this with other factor types." },
  { id:30344, domain:5, level:2, question:"What is the primary purpose of Privileged Access Management (PAM) solutions?", options:["A Managing end-user passwords across multiple applications","B Automating the provisioning of new user accounts in directory services","C Providing single sign-on for regular user accounts across enterprise applications","D Controlling, monitoring, and auditing privileged account usage to minimize insider threat risk"], correct:3, explanation:"PAM solutions control access to privileged accounts (admin, root, service accounts), enforce least privilege, record privileged sessions, and provide audit trails to detect and prevent misuse of elevated credentials." },
  { id:30345, domain:5, level:2, question:"What does the concept of 'identity federation' enable?", options:["A Trust relationships between domains allowing users to authenticate once and access resources across boundaries","B Central storage of all user identities across every connected organization","C Automatic synchronization of passwords between multiple identity stores","D Mandatory use of the same authentication protocol across all federated systems"], correct:0, explanation:"Identity federation establishes trust between organizations (or domains) so that authenticated users can access resources in partner organizations without needing separate accounts, based on trusted identity assertions." },
  { id:30346, domain:5, level:2, question:"Which protocol is commonly used for centralized authentication, authorization, and accounting in network access scenarios?", options:["A LDAP","B OAuth 2.0","C RADIUS","D TACACS+"], correct:2, explanation:"RADIUS (Remote Authentication Dial-In User Service) provides centralized AAA services for network access, commonly used for VPN, Wi-Fi, and dial-up authentication. TACACS+ provides similar functionality with additional features for device administration." },
  { id:30347, domain:5, level:2, question:"What is the difference between authentication and authorization?", options:["A Authentication is performed by the client; authorization is performed by the server","B Authentication determines what you can do; authorization verifies who you are","C Authentication verifies who you are; authorization determines what you are permitted to do","D Authentication applies to users; authorization applies only to service accounts"], correct:2, explanation:"Authentication verifies identity (who are you?), while authorization determines access rights (what are you allowed to do?). Both are required for secure access control, but they are distinct processes." },
  { id:30348, domain:5, level:2, question:"What is a directory service's primary function in identity management?", options:["A Providing encrypted storage for user credentials and private keys","B Generating one-time passwords for multi-factor authentication","C Auditing and logging all user access events for compliance reporting","D Storing and providing access to information about network resources and users"], correct:3, explanation:"Directory services (e.g., Active Directory, LDAP) store structured information about network objects (users, groups, computers, resources) and provide query and update capabilities, serving as the foundation for authentication and authorization." },
  { id:30349, domain:5, level:2, question:"What is the purpose of access recertification (access review) campaigns?", options:["A Resetting all user passwords on a scheduled basis for security hygiene","B Auditing failed authentication attempts to detect potential intrusions","C Updating access control policies to reflect new business requirements","D Periodically reviewing and confirming that user access rights remain appropriate and necessary"], correct:3, explanation:"Access recertification involves periodic reviews by managers or data owners to confirm that users' access rights are still appropriate for their current role, removing unnecessary or excessive access to maintain least privilege." },
  { id:30350, domain:5, level:2, question:"Which concept ensures that no single person can complete a sensitive transaction or task without involvement from another person?", options:["A Least privilege","B Separation of duties","C Need to know","D Job rotation"], correct:1, explanation:"Separation of duties (SoD) divides critical tasks between multiple people so that no single individual can misuse access or commit fraud without detection. For example, the person who authorizes payments should not also process them." },
  { id:30351, domain:3, level:2, question:"Which security model is based on the concept of Chinese Wall and prevents conflicts of interest?", options:["A Bell-LaPadula model","B Brewer-Nash (Chinese Wall) model","C Biba model","D Clark-Wilson model"], correct:1, explanation:"The Brewer-Nash model (Chinese Wall) prevents conflicts of interest by restricting access to competing companies' data once a user has accessed one company's data, commonly used in financial and consulting environments." },
  { id:30352, domain:3, level:2, question:"What is the primary purpose of a hardware security module (HSM)?", options:["A Providing a secure network perimeter for server rooms","B Monitoring hardware performance and detecting physical intrusions","C Generating, storing, and managing cryptographic keys in tamper-resistant hardware","D Enforcing hardware-level access controls for server BIOS settings"], correct:2, explanation:"HSMs are dedicated hardware devices that generate, store, and protect cryptographic keys and perform cryptographic operations in a tamper-resistant environment, protecting keys from extraction even by administrators." },
  { id:30353, domain:3, level:2, question:"What is steganography used for in information security?", options:["A Encrypting data using a one-time pad for perfect secrecy","B Authenticating digital messages using asymmetric key pairs","C Compressing data before encryption to improve efficiency","D Hiding secret information within ordinary non-secret data or files"], correct:3, explanation:"Steganography conceals the existence of a message by embedding it within another medium (image, audio, video, text) without visibly altering the carrier, used for covert communication or digital watermarking." },
  { id:30354, domain:3, level:2, question:"What does 'complete mediation' mean as a security design principle?", options:["A Every access request must go through an arbitration process involving multiple parties","B Every access to every object must be checked against the access control policy every time","C Security decisions require input from both the user and the system administrator","D Access controls are mediated by a central policy enforcement point only once per session"], correct:1, explanation:"Complete mediation requires that every access to every object be checked against the access control policy each time, preventing attacks that exploit cached or assumed permissions from a prior authorization check." },
  { id:30355, domain:3, level:2, question:"Which of the following best describes a covert channel?", options:["A An encrypted communication channel used by insider threat actors","B A hidden network interface used to bypass firewall rules","C A communication channel that violates security policy by transmitting information through unintended means","D A stealthy malware command-and-control mechanism using social media"], correct:2, explanation:"A covert channel is a communication path that was not intended for communication and violates security policy. Covert storage channels use storage objects; covert timing channels exploit shared system resources." },
  { id:30356, domain:3, level:2, question:"What is the purpose of key derivation functions (KDFs) like PBKDF2 or bcrypt?", options:["A Generating asymmetric key pairs from random seed values","B Distributing encryption keys securely across distributed systems","C Converting symmetric keys to asymmetric keys for hybrid encryption","D Deriving cryptographic keys from passwords using intentional computational expense to slow attackers"], correct:3, explanation:"KDFs derive cryptographic keys from passwords or passphrases, using salt and iterative hashing to make the derivation computationally expensive, significantly slowing brute-force and dictionary attacks." },
  { id:30357, domain:3, level:2, question:"What does the concept of 'fail secure' (fail safe) mean in system design?", options:["A Systems should automatically recover from failure without human intervention","B When a system fails, it should default to a secure state denying access","C Redundant systems ensure no failure can occur during critical operations","D Security mechanisms remain active even during software updates"], correct:1, explanation:"Fail secure (fail safe) means that when a system fails or encounters an error, it defaults to denying access or taking the most restrictive action, preventing failures from creating security vulnerabilities." },
  { id:30358, domain:3, level:2, question:"Which cryptographic primitive provides both confidentiality and integrity in a single operation?", options:["A RSA encryption","B HMAC","C Authenticated Encryption with Associated Data (AEAD)","D Diffie-Hellman key exchange"], correct:2, explanation:"AEAD modes (like AES-GCM or ChaCha20-Poly1305) provide confidentiality through encryption and authenticity/integrity through authentication tags in a single operation, preventing padding oracle and ciphertext tampering attacks." },
  { id:30359, domain:3, level:2, question:"What is the purpose of a digital signature?", options:["A To encrypt data so only the intended recipient can read it","B To authenticate the sender using a shared secret key","C To provide non-repudiation and integrity verification using the sender's private key","D To create a secure channel for key exchange between parties"], correct:2, explanation:"Digital signatures use the sender's private key to sign data, allowing recipients to verify integrity and non-repudiation (the sender cannot deny signing). The signature is verified using the sender's public key." },
  { id:30360, domain:3, level:2, question:"Which hashing algorithm produces a 256-bit output and is recommended for most security applications?", options:["A MD5","B SHA-256","C SHA-1","D CRC-32"], correct:1, explanation:"SHA-256 (part of the SHA-2 family) produces a 256-bit hash, is computationally secure against collision attacks, and is widely recommended for digital signatures, certificates, and data integrity verification." },
  { id:30361, domain:4, level:2, question:"What type of DNS attack involves poisoning the resolver cache with false records to redirect traffic?", options:["A DNS amplification attack","B DNS zone transfer exploit","C DNS tunneling attack","D DNS cache poisoning (DNS spoofing)"], correct:3, explanation:"DNS cache poisoning injects malicious DNS records into a resolver's cache, causing it to return incorrect IP addresses for domain names, redirecting users to attacker-controlled servers for phishing or malware distribution." },
  { id:30362, domain:4, level:2, question:"What is DNS Security Extensions (DNSSEC) designed to prevent?", options:["A Encrypted DNS queries from being intercepted by ISPs","B Unauthorized zone transfers between DNS servers","C DNS amplification attacks by rate-limiting recursive queries","D DNS cache poisoning by providing cryptographic authentication of DNS responses"], correct:3, explanation:"DNSSEC adds cryptographic signatures to DNS records, allowing resolvers to verify that responses are authentic and unmodified, preventing cache poisoning and man-in-the-middle attacks on DNS resolution." },
  { id:30363, domain:4, level:2, question:"Which network protocol uses both UDP and TCP on port 53?", options:["A DNS","B HTTP","C SMTP","D SNMP"], correct:0, explanation:"DNS uses UDP port 53 for standard queries (faster, lower overhead) and TCP port 53 for responses exceeding 512 bytes and zone transfers, which require reliable transmission." },
  { id:30364, domain:4, level:2, question:"What is the primary risk associated with using Telnet for remote server administration?", options:["A Telnet sessions cannot be terminated gracefully if the connection is lost","B Telnet does not support authentication mechanisms","C Telnet transmits all data including credentials in cleartext","D Telnet only supports IPv4 and not modern IPv6 networks"], correct:2, explanation:"Telnet transmits all data, including usernames and passwords, in plaintext without encryption. SSH should be used instead, as it provides encrypted authentication and session data." },
  { id:30365, domain:4, level:2, question:"What does the principle of network segmentation accomplish for security?", options:["A It prevents all users from accessing the internet directly","B It eliminates the need for perimeter firewalls in modern network designs","C It limits lateral movement by containing breaches and restricting unnecessary inter-segment traffic","D It ensures all traffic is inspected by an application-layer proxy"], correct:2, explanation:"Network segmentation divides networks into smaller segments, limiting the blast radius of a security incident by preventing attackers from freely moving laterally between systems once they compromise one segment." },
  { id:30366, domain:4, level:2, question:"Which technology creates virtual isolated network segments within a shared physical network infrastructure?", options:["A VPN (Virtual Private Network)","B DMZ (Demilitarized Zone)","C VLAN (Virtual Local Area Network)","D SDN (Software-Defined Networking)"], correct:2, explanation:"VLANs create logical network segments on shared physical infrastructure, controlling broadcast domains and implementing network segmentation without requiring separate physical hardware for each network segment." },
  { id:30367, domain:4, level:2, question:"What is the primary purpose of a demilitarized zone (DMZ) in network architecture?", options:["A To host public-facing services in a network segment isolated from both the internet and internal network","B To isolate administrator workstations from regular user networks","C To provide a buffer zone where all traffic is decrypted for inspection","D To segment wireless access points from wired infrastructure"], correct:0, explanation:"A DMZ is a network segment between the internet and the internal network that hosts public-facing servers (web, mail, DNS). It limits exposure so that if a public server is compromised, attackers don't have direct access to the internal network." },
  { id:30368, domain:4, level:2, question:"Which type of IDS/IPS detection method creates a baseline of normal behavior and alerts on deviations?", options:["A Signature-based detection","B Rule-based detection","C Anomaly-based (behavior-based) detection","D Protocol-based detection"], correct:2, explanation:"Anomaly-based detection establishes a baseline of normal network or system behavior and alerts when activity deviates significantly from that baseline, allowing detection of unknown or novel attacks but with higher false positive rates." },
  { id:30369, domain:4, level:2, question:"What is the main limitation of signature-based intrusion detection systems?", options:["A They require dedicated hardware and cannot run as software solutions","B They can only monitor network traffic, not host-based activities","C They generate too many false positives for practical deployment","D They cannot detect zero-day attacks or malware without a matching signature"], correct:3, explanation:"Signature-based IDS/IPS rely on known attack patterns (signatures) and cannot detect novel or zero-day attacks that don't match any existing signature in their database." },
  { id:30370, domain:4, level:2, question:"What is a 'sinkhole' in the context of network security?", options:["A A honeypot designed to attract and analyze botnet traffic","B A network device that absorbs and drops all inbound DDoS traffic","C A routing technique that redirects malicious traffic to a controlled destination for analysis","D A deep packet inspection system monitoring DNS queries"], correct:2, explanation:"DNS/route sinkholing redirects traffic destined for known malicious domains/IPs to a controlled server, preventing malware from reaching command-and-control servers and allowing analysis of infected systems." },
  { id:30371, domain:4, level:2, question:"What protocol does HTTPS use to secure web communications?", options:["A IPSec","B SFTP (Secure File Transfer Protocol)","C SSH (Secure Shell)","D TLS (Transport Layer Security)"], correct:3, explanation:"HTTPS uses TLS (formerly SSL) to encrypt HTTP communications, providing confidentiality, integrity, and server authentication (via certificates) for web traffic." },
  { id:30372, domain:4, level:2, question:"Which TLS component verifies the server's identity to the client?", options:["A The session key","B The client hello message","C The cipher suite negotiation","D The server's digital certificate"], correct:3, explanation:"The server's digital certificate (issued by a trusted Certificate Authority) contains the server's public key and identity information. Clients verify the certificate to authenticate the server before trusting the connection." },
  { id:30373, domain:4, level:2, question:"What is perfect forward secrecy (PFS) in TLS?", options:["A Generating unique session keys so compromising the server's private key doesn't compromise past sessions","B Using the same session key for all connections to improve efficiency","C Ensuring all TLS versions support backward compatibility with older clients","D Encrypting the TLS handshake to prevent traffic analysis"], correct:0, explanation:"PFS (using ephemeral Diffie-Hellman or ECDH key exchange) generates unique session keys for each connection. Even if the server's long-term private key is later compromised, past encrypted sessions cannot be decrypted." },
  { id:30374, domain:4, level:2, question:"Which network security technology monitors and filters web traffic based on content and URL categories?", options:["A Network-based IPS","B Email security gateway","C Next-generation firewall","D Secure Web Gateway (SWG)"], correct:3, explanation:"A Secure Web Gateway provides URL filtering, malware inspection, data loss prevention, and SSL inspection for outbound web traffic, enforcing acceptable use policies and blocking malicious content." },
  { id:30375, domain:4, level:2, question:"What type of attack uses multiple systems to overwhelm a target's resources with traffic?", options:["A Man-in-the-middle attack","B Cross-site request forgery attack","C Session hijacking attack","D Distributed Denial of Service (DDoS) attack"], correct:3, explanation:"DDoS attacks coordinate many compromised systems (botnet) to simultaneously flood a target with traffic or requests, exhausting bandwidth, processing capacity, or connections to render the service unavailable." },
  { id:30376, domain:5, level:2, question:"What is the purpose of a Password Authentication Protocol (PAP) replacement like CHAP?", options:["A To eliminate the need for password-based authentication entirely","B To avoid transmitting the actual password over the network by using challenge-response","C To encrypt all PAP authentication exchanges using TLS","D To allow users to authenticate with multiple passwords for redundancy"], correct:1, explanation:"CHAP (Challenge Handshake Authentication Protocol) uses a challenge-response mechanism where only a hash of the password is transmitted, not the password itself, preventing interception attacks that affect PAP." },
  { id:30377, domain:5, level:2, question:"What is the primary security benefit of using smart cards for authentication?", options:["A Smart cards are cheaper to deploy than password-based systems","B Smart cards provide two-factor authentication combining something you have with something you know","C Smart cards eliminate the need for a PKI infrastructure","D Smart cards cannot be replicated or duplicated under any circumstances"], correct:1, explanation:"Smart cards combine a physical card (something you have) with a PIN (something you know), providing two-factor authentication. The private key never leaves the card, preventing extraction attacks." },
  { id:30378, domain:5, level:2, question:"What does SCIM (System for Cross-domain Identity Management) provide?", options:["A Standardized API for automating user provisioning and deprovisioning across multiple systems","B Encrypted transmission of identity attributes between identity providers","C Single sign-on capability for cloud-based applications","D Certificate-based authentication for mobile device management"], correct:0, explanation:"SCIM is an open standard protocol that automates the exchange of user identity information between identity providers and service providers, standardizing user provisioning/deprovisioning to reduce administrative overhead." },
  { id:30379, domain:5, level:2, question:"Which concept limits the damage from a compromised account by ensuring it has only the minimum permissions needed?", options:["A Defense in depth","B Separation of duties","C Mandatory access control","D Principle of least privilege"], correct:3, explanation:"The principle of least privilege grants accounts, processes, and users only the minimum permissions required for their specific tasks, limiting the blast radius if credentials are compromised." },
  { id:30380, domain:5, level:2, question:"What is the difference between identification and authentication?", options:["A Identification is performed by the server; authentication is performed by the client","B Identification claims an identity; authentication proves that the claimed identity is genuine","C Identification uses passwords; authentication uses biometrics","D Identification is a one-time process; authentication occurs at every login"], correct:1, explanation:"Identification is the act of claiming an identity (e.g., entering a username). Authentication is the process of proving the claimed identity is genuine (e.g., providing a password, token, or biometric)." },
  { id:30381, domain:5, level:2, question:"What is the primary purpose of a centralized identity management system?", options:["A Managing user identities, access rights, and provisioning from a single authoritative source","B Providing faster authentication by caching credentials locally on each device","C Eliminating the need for access control policies across connected systems","D Automatically granting users all permissions needed for their department"], correct:0, explanation:"Centralized identity management provides a single authoritative source for user identities, roles, and access rights, simplifying provisioning/deprovisioning, ensuring consistency, and improving audit capabilities." },
  { id:30382, domain:5, level:2, question:"Which access control type uses rules defined by system administrators and cannot be changed by data owners?", options:["A Mandatory Access Control (MAC)","B Discretionary Access Control (DAC)","C Role-Based Access Control (RBAC)","D Attribute-Based Access Control (ABAC)"], correct:0, explanation:"In MAC, access control policies are set by administrators or the system based on security labels, and individual data owners cannot override these rules. This is commonly used in military/government environments." },
  { id:30383, domain:5, level:2, question:"What is OpenID Connect (OIDC) built on top of?", options:["A SAML 2.0 for identity federation","B OAuth 2.0, adding an identity layer for authentication","C Kerberos for distributed authentication","D LDAP for directory-based identity management"], correct:1, explanation:"OpenID Connect is an authentication layer built on top of OAuth 2.0. It adds an ID token (JWT) that contains user identity information, enabling both authentication and authorization in a single framework." },
  { id:30384, domain:5, level:2, question:"What is a common attack against Kerberos that involves requesting many service tickets to crack offline?", options:["A Pass-the-hash attack","B Golden ticket attack","C Kerberoasting attack","D Silver ticket attack"], correct:2, explanation:"Kerberoasting requests service tickets for SPNs, then attempts to crack them offline. Since service tickets are encrypted with the service account's password hash, weak passwords can be recovered without triggering online authentication failures." },
  { id:30385, domain:5, level:2, question:"What does a 'golden ticket' attack in Kerberos allow an attacker to do?", options:["A Forge authentication cookies for any web application","B Bypass multi-factor authentication for privileged accounts","C Forge Kerberos TGTs to impersonate any user, including administrators, by knowing the KRBTGT hash","D Create fake X.509 certificates to impersonate servers"], correct:2, explanation:"A golden ticket attack forges Ticket Granting Tickets using the compromised KRBTGT account hash, allowing the attacker to impersonate any user in the domain with any group membership, providing persistent domain-wide access." },
  { id:30386, domain:5, level:2, question:"Which authentication method involves verifying a user's identity based on behavioral patterns over time?", options:["A Multi-factor authentication","B Knowledge-based authentication","C Certificate-based authentication","D Continuous authentication (behavioral biometrics)"], correct:3, explanation:"Continuous authentication (behavioral biometrics) monitors patterns like typing cadence, mouse movements, and usage behavior throughout a session to continuously verify user identity, detecting session hijacking or account takeover." },
  { id:30387, domain:5, level:2, question:"What is the primary security issue with shared accounts (generic accounts)?", options:["A Shared accounts are more difficult to manage in Active Directory","B Shared accounts prevent individual accountability and complicate audit trails","C Shared accounts require more complex password policies to maintain","D Shared accounts are incompatible with most modern authentication protocols"], correct:1, explanation:"Shared accounts (e.g., 'admin' used by multiple people) break individual accountability. It's impossible to determine which individual performed specific actions, violating non-repudiation and making forensic investigation difficult." },
  { id:30388, domain:5, level:2, question:"What is a time-based one-time password (TOTP)?", options:["A A password generated from a shared secret and current time, valid only briefly","B A password valid only during business hours to limit unauthorized access","C A password that changes after a fixed number of authentication attempts","D A temporary password sent via SMS that expires after first use"], correct:0, explanation:"TOTP generates authentication codes from a shared secret combined with the current time (typically 30-second windows), producing short-lived codes that are valid only briefly, preventing replay attacks." },
  { id:30389, domain:5, level:2, question:"What is the primary advantage of FIDO2/WebAuthn for authentication?", options:["A It eliminates the need for any form of user verification","B It provides phishing-resistant authentication using public key cryptography tied to the origin","C It is backward compatible with all legacy password-based systems","D It requires only a username without any additional factor"], correct:1, explanation:"FIDO2/WebAuthn uses asymmetric cryptography where the private key never leaves the authenticator and the key is bound to the specific origin, making it resistant to phishing because credentials cannot be reused on fake sites." },
  { id:30390, domain:5, level:2, question:"What is account harvesting in the context of identity attacks?", options:["A Extracting all user accounts from a compromised directory service","B Enumerating valid usernames through login error messages or timing differences","C Collecting user credentials from phishing campaigns over time","D Aggregating identity information from multiple breached databases"], correct:1, explanation:"Account harvesting exploits authentication systems that reveal whether a username exists (through different error messages or response times), allowing attackers to enumerate valid accounts for targeted credential attacks." },
  { id:30391, domain:3, level:2, question:"What is the role of a Certificate Authority (CA) in a PKI?", options:["A To store all private keys for recovery purposes","B To issue, sign, and revoke digital certificates binding identities to public keys","C To encrypt all communications between clients and servers","D To manage access control policies for certificate holders"], correct:1, explanation:"A CA is a trusted third party that issues digital certificates, vouching for the binding between an entity's identity and its public key. The CA signs certificates with its own private key, allowing others to verify authenticity." },
  { id:30392, domain:3, level:2, question:"What is a Certificate Revocation List (CRL)?", options:["A A list of certificates that have been revoked before their expiration date","B A list of certificates pending issuance by a Certificate Authority","C A list of approved certificate algorithms and key lengths","D A database of all certificates issued by a Certificate Authority"], correct:0, explanation:"A CRL is a list published by a CA containing serial numbers of certificates that have been revoked (due to key compromise, personnel changes, etc.) before their scheduled expiration. Applications check CRLs to reject revoked certificates." },
  { id:30393, domain:3, level:2, question:"What advantage does OCSP (Online Certificate Status Protocol) provide over CRL?", options:["A OCSP provides better encryption than CRL-based verification","B OCSP eliminates the need for Certificate Authorities to revoke certificates","C OCSP provides real-time certificate status without downloading large CRL files","D OCSP allows certificates to be verified without network connectivity"], correct:2, explanation:"OCSP allows real-time certificate status checking by querying the CA's OCSP responder, avoiding the overhead of downloading potentially large CRL files and providing more timely revocation status." },
  { id:30394, domain:3, level:2, question:"What is the key escrow concept in cryptography?", options:["A Encrypting backup copies of keys with a secondary key pair","B Storing encryption keys in a physically secure hardware vault","C Splitting keys between multiple administrators using secret sharing","D Temporary transfer of encryption keys to a trusted third party for lawful access"], correct:3, explanation:"Key escrow involves depositing copies of encryption keys with a trusted third party (often a government agency or compliance officer) so that encrypted data can be accessed under lawful authority or for business continuity purposes." },
  { id:30395, domain:3, level:2, question:"What does 'security through obscurity' mean and why is it considered a weak security strategy?", options:["A Using complex encryption algorithms that attackers find difficult to understand","B Limiting public documentation about security controls to prevent enumeration","C Hiding systems behind network address translation to obscure their true addresses","D Relying on secrecy of design or implementation as the primary security mechanism, which fails when secrets are exposed"], correct:3, explanation:"Security through obscurity relies on keeping system design, vulnerabilities, or configurations secret. It is weak because once the secret is discovered (through reverse engineering, leaks, or research), all security disappears. Defense should not depend on obscurity." },
  { id:30396, domain:3, level:2, question:"What is the Diffie-Hellman protocol used for?", options:["A Securely establishing a shared secret key over an untrusted channel","B Encrypting messages using asymmetric public key encryption","C Generating and verifying digital signatures for message authentication","D Providing certificate-based authentication in PKI environments"], correct:0, explanation:"Diffie-Hellman allows two parties to establish a shared secret key over an insecure channel without previously sharing any secret information, by exchanging public values and computing a common secret from their private values." },
  { id:30397, domain:4, level:2, question:"What is 'network access control' (NAC)?", options:["A Enforcing security policy compliance before granting devices access to the network","B Filtering network traffic based on application-layer content inspection","C Managing network administrator credentials for device configuration","D Controlling user access to specific network resources based on roles"], correct:0, explanation:"NAC evaluates endpoint compliance (patches, AV, configuration) before granting network access, quarantining non-compliant devices, ensuring only healthy and policy-compliant devices connect to the network." },
  { id:30398, domain:4, level:2, question:"What is the primary security risk of BYOD (Bring Your Own Device) policies?", options:["A Personal devices are typically slower than corporate devices","B Personal devices are incompatible with enterprise authentication protocols","C BYOD increases helpdesk costs for device support","D Personal devices may not meet corporate security standards and can introduce vulnerabilities"], correct:3, explanation:"BYOD introduces risks including unpatched personal devices, mixing personal and corporate data, difficulty enforcing security policies, and challenges with device management and remote wipe of corporate data." },
  { id:30399, domain:4, level:2, question:"What does a next-generation firewall (NGFW) provide beyond traditional stateful inspection?", options:["A Hardware-accelerated encryption for all network traffic","B Automated vulnerability scanning of connected network devices","C Application awareness, user identity integration, and deep packet inspection capabilities","D Physical port security and MAC address filtering for endpoints"], correct:2, explanation:"NGFWs provide traditional stateful inspection plus application-layer (Layer 7) awareness, user identity integration, SSL/TLS inspection, IPS capabilities, and threat intelligence feeds, enabling policy enforcement based on applications and users." },
  { id:30400, domain:4, level:2, question:"What security mechanism does 802.1AE (MACsec) provide?", options:["A Wireless network encryption for enterprise Wi-Fi deployments","B Encrypted tunneling for site-to-site VPN connections","C Multi-factor authentication for network device access","D Layer 2 encryption and authentication for wired Ethernet frames"], correct:3, explanation:"MACsec (802.1AE) provides hop-by-hop encryption and authentication at Layer 2 (Ethernet), securing traffic between directly connected devices and protecting against eavesdropping and tampering on local network segments." }
];
